24	{
25	    public class TrainRailConnectSystem : IPlaceSystem
26	    {
27	        private readonly RailConnectPreviewObject _previewObject;
28	        private readonly Camera _mainCamera;
29	        private readonly RailGraphClientCache _cache;
30	        private readonly ILocalPlayerInventory _playerInventory;
31	        private readonly TrainRailPlaceSystemService _trainRailPlaceSystemService;
32	        private readonly BlockGameObjectDataStore _blockGameObjectDataStore;
33	        
34	        private IRailComponentConnectAreaCollider _connectFromArea;
35	        public TrainRailConnectSystem(Camera mainCamera, IPlacementPreviewBlockGameObjectController controller, RailConnectPreviewObject previewObject, RailGraphClientCache cache, LocalPlayerInventoryController localPlayerInventory, BlockGameObjectDataStore blockGameObjectDataStore)
36	        {
37	            _mainCamera = mainCamera;
38	            _previewObject = previewObject;
39	            _cache = cache;
40	            _playerInventory = localPlayerInventory.LocalPlayerInventory;
41	            _trainRailPlaceSystemService = new TrainRailPlaceSystemService(mainCamera, controller);
42	            _blockGameObjectDataStore = blockGameObjectDataStore;
43	        }
44	        
45	        public void Enable()
46	        {
47	            _connectFromArea = null;
48	        }
49	        public void ManualUpdate(PlaceSystemUpdateContext context)
50	        {
51	            _trainRailPlaceSystemService.Disable();
52	            
53	            // 接続元が未選択なら接続元を選択する
54	            // If the connection source is not selected, select the connection source.
55	            if (_connectFromArea == null)
56	            {
57	                if (InputManager.Playable.ScreenLeftClick.GetKeyDown)
58	                {
59	                    _connectFromArea = GetTrainRailConnectAreaCollider();
60	                }
61	                if (_connectFromArea != null)
62	                {
63	                    var destination = _connectFromArea.CreateConnectionDestination();
64	                    var componentPosition = destination.blockPosition;
65	                    Debug.Log($"[TrainRailConnect] Select FROM: IsFront={_connectFromArea.IsFront} pos=({componentPosition.x},{componentPosition.y},{componentPosition.z})");
66	                }
67	                return;
68	            }
69	            
70	            // Compute ConnectionDestination for both endpoints
71	            var fromDestination = _connectFromArea.CreateConnectionDestination();
72	            
73	            // If the connection point is not under the cursor, return.
74	            var connectToArea = GetTrainRailConnectAreaCollider();
75	            if (connectToArea == null)
76	            {
77	                if (PlaceSystemUtil.TryGetRayHitPosition(_mainCamera, out var position, out _))
78	                {
79	                    _trainRailPlaceSystemService.Enable();
80	                    
81	                    (IItemStack stack, int i)[] pierSlots = _playerInventory.Select((stack, i) => (stack, i)).Where(itemStack =>
82	                    {
83	                        if (!MasterHolder.BlockMaster.IsBlock(itemStack.stack.Id)) return false;
84	                        var blockId = MasterHolder.BlockMaster.GetBlockId(itemStack.stack.Id);
85	                        var blockMasterElement = MasterHolder.BlockMaster.GetBlockMaster(blockId);
86	                        return blockMasterElement.BlockType == BlockMasterElement.BlockTypeConst.TrainRail;
87	                    }).ToArray();
88	                    
89	                    if (!pierSlots.Any())
90	                    {
91	                        // pierがない場合は設置不可。仮にデフォルトの最大長で判定する
92	                        // No pier in inventory: still preview with default max length
93	                        var previewData = CalculatePreviewData(fromDestination, position, _trainRailPlaceSystemService.RailDirection, _cache, _playerInventory, _blockGameObjectDataStore, float.MaxValue, context.HoldingItemId);
94	                        ShowPreview(previewData);
95	                    }
96	                    else
97	                    {
98	                        // pierがある場合は設置可能。配置予定の TrainRail ブロックの最大長を参照する
99	                        // Pier available: pass the placing TrainRail block's max length
100	                        var (itemStack, pierInventorySlot) = pierSlots.First();
101	                        var pierBlockId = MasterHolder.BlockMaster.GetBlockId(itemStack.Id);
102	                        var pierBlockMaster = MasterHolder.BlockMaster.GetBlockMaster(pierBlockId);
103	                        var pierMaxLength = TrainRailConnectPreviewCalculator.GetMaxConnectableRailLength(pierBlockMaster);
104	                        var placeInfo = _trainRailPlaceSystemService.ManualUpdate(itemStack.Id);
105	                        var previewData = CalculatePreviewData(fromDestination, _trainRailPlaceSystemService.ConnectorPosition, _trainRailPlaceSystemService.RailDirection, _cache, _playerInventory, _blockGameObjectDataStore, pierMaxLength, context.HoldingItemId);
106	                        ShowPreview(previewData);
107	
108	                        if (!previewData.IsPlaceable) return;
109	
110	                        // 設置
111	                        SendConnectRailWithPlacePierProtocol(placeInfo, previewData.RailTypeGuid, pierInventorySlot);
112	                    }
113	                }
114	            }
115	            else
116	            {
117	                var toDestination = connectToArea.CreateConnectionDestination();
118	                toDestination.IsFront = !toDestination.IsFront;
119	                if (fromDestination.IsDefault() || toDestination.IsDefault())
120	                {
121	                    Debug.LogWarning("[TrainRailConnect] Invalid destination detected. Re-select connection target.");
122	                    _previewObject.SetActive(false);
123	                    return;
124	                }
125	                
126	                if (!TryResolveNode(fromDestination, out var fromNode) ||
127	                    !TryResolveNode(toDestination, out var toNode))
128	                {
129	                    Debug.LogWarning("[TrainRailConnect] Failed to resolve node info from cache.");
130	                    _connectFromArea = null;
131	                    return;
132	                }
133	                
134	                var previewData = CalculatePreviewData(fromDestination, toDestination, _cache, _playerInventory, _blockGameObjectDataStore, context.HoldingItemId);
135	                ShowPreview(previewData);
136	
137	                if (!previewData.IsPlaceable) return;
138	
139	                SendConnectRailProtocol(fromNode, toNode, previewData.RailTypeGuid);
140	            }
141	            
142	            #region Internal
143	            
144	            void ShowPreview(TrainRailConnectPreviewData previewData)
145	            {
146	                if (!previewData.IsValid)
147	                {
148	                    _previewObject.SetActive(false);
149	                    return;
150	                }
151	                _previewObject.SetActive(true);
152	                _previewObject.ShowPreview(previewData);
153	            }
154	            
155	            void SendConnectRailProtocol(IRailNode from, IRailNode to, Guid railTypeGuid)
156	            {
157	                if (!InputManager.Playable.ScreenLeftClick.GetKeyDown) return;
158	                
159	                _previewObject.SetActive(false);
160	                
161	                Debug.Log($"Connecting rails: From NodeId={from.NodeId}, Guid={from.NodeGuid} To NodeId={to.NodeId}, Guid={to.NodeGuid}");
162	                ClientContext.VanillaApi.SendOnly.ConnectRail(from.NodeId, from.NodeGuid, to.NodeId, to.NodeGuid, railTypeGuid);
163	                _connectFromArea = null;
164	            }
165	            
166	            void SendConnectRailWithPlacePierProtocol(PlaceInfo placeInfo, Guid railTypeGuid, int pierInventorySlot)
167	            {
168	                if (!InputManager.Playable.ScreenLeftClick.GetKeyDown) return;
169	                if (!TryResolveNode(fromDestination, out var fromNode)) return;
170	                
171	                _previewObject.SetActive(false);
172	                
173	                _connectFromArea = null;
174	                
175	                UniTask.Create(async () =>
176	                {
177	                    var response = await ClientContext.VanillaApi.Response.PlaceRailWithPier(fromNode.NodeId, fromNode.NodeGuid, pierInventorySlot, placeInfo, railTypeGuid, CancellationToken.None);
178	                    if (!response.Success) return;
179	                    
180	                    await UniTask.WhenAny(
181	                        UniTask.WaitForSeconds(1f),
182	                        UniTask.WaitUntil(() => _cache.TryGetNode(response.ToNodeId, out _))
183	                    );
184	                    
185	                    if (_cache.TryGetNode(response.ToNodeId, out var node))
186	                    {
187	                        var pierBlock = _blockGameObjectDataStore.GetBlockGameObject(node.ConnectionDestination.blockPosition);
188	                        TrainRailConnectAreaCollider[] areas = pierBlock.gameObject.GetComponentsInChildren<TrainRailConnectAreaCollider>();
189	                        var area = areas.First(area =>
190	                        {
191	                            if (_cache.TryGetNodeId(area.CreateConnectionDestination(), out var nodeId) && _cache.TryGetNode(nodeId, out var clientNode))
192	                            {
193	                                return clientNode.NodeId == node.NodeId && clientNode.NodeGuid == node.NodeGuid;
194	                            }
195	                            
196	                            return false;
197	                        });
198	                        
199	                        _connectFromArea = area;
200	                        Debug.Log("PierBlock", pierBlock);
201	                    }
202	                });
203	            }
204	            
205	            IRailComponentConnectAreaCollider GetTrainRailConnectAreaCollider()
206	            {
207	                PlaceSystemUtil.TryGetRaySpecifiedComponentHit<IRailComponentConnectAreaCollider>(_mainCamera, out var connectArea, Without_Player_MapObject_BlockBoundingBox_LayerMask);
208	                return connectArea;
209	            }
210	            
211	            bool TryResolveNode(ConnectionDestination destination, out IRailNode railNode)
212	            {
213	                railNode = null;
214	                return _cache.TryGetNodeId(destination, out var nodeId) && _cache.TryGetNode(nodeId, out railNode);
215	            }
216	            
217	            #endregion
218	        }
219	        public void Disable()
220	        {
221	            _previewObject.SetActive(false);
222	            _trainRailPlaceSystemService.Disable();
223	        }
224	    }
225	}
