19	    ///     Operations for the UI route: build menu, placement preview, and click-to-place
20	    /// </summary>
21	    public static class PlaytestUiOps
22	    {
23	        public static UIStateEnum CurrentUiState()
24	        {
25	            return Object.FindFirstObjectByType<UIStateControl>().CurrentState;
