40	        public static async UniTask OpenBuildMenuAndSelectBlock(string blockName)
41	        {
42	            // ビルドメニューを開き、対象ブロックのスロットをEventSystem経由でクリックする
43	            // Open the build menu, then click the target block's slot through the EventSystem
44	            // PlaceBlock中はBだとGameScreenへ抜けてしまうためTabで開き直す（実プレイと同じキー割当）
45	            // While in PlaceBlock, B exits to GameScreen, so reopen with Tab (same binding as real play)
46	            if (CurrentUiState() == UIStateEnum.PlaceBlock)
47	            {
