81	        public static Vector3 PlaceAimPoint(string blockName, Vector3Int origin, BlockDirection direction)
82	        {
83	            // CalcPlacePointの逆算: 接地面上のフットプリント中心を狙えば指定originに設置される
84	            // Inverse of CalcPlacePoint: aiming at the footprint center on the ground surface yields the given origin
85	            var blockId = PlaytestBlockOps.ResolveBlockId(blockName);
