10	using UnityEngine;
11	using VContainer;
12	
13	namespace Client.Playtest.Operations
14	{
15	    /// <summary>
16	    ///     アイテム付与・在庫確認の操作群。Direct（サーバー直挿入）とViaCommand（本番givePath）の2経路を提供
17	    ///     Item grant/inventory helpers with two paths: Direct (server insert) and ViaCommand (production give path)
18	    /// </summary>
19	    public static class PlaytestItemOps
20	    {
21	        public static ItemId ResolveItemId(string itemName)
22	        {
23	            foreach (var itemId in MasterHolder.ItemMaster.GetItemAllIds())
24	            {
25	                if (MasterHolder.ItemMaster.GetItemMaster(itemId).Name == itemName) return itemId;
26	            }
27	            throw new ArgumentException($"Item not found: {itemName}");
28	        }
29	
30	        public static void GiveItemDirect(string itemName, int count)
31	        {
32	            // サーバーのインベントリへ同期的に直接挿入する（待機不要・状態を素早く作る用）
33	            // Insert synchronously into the server inventory (no wait; for fast state setup)
34	            var itemId = ResolveItemId(itemName);
35	            var playerId = ClientContext.PlayerConnectionSetting.PlayerId;
36	            var itemStack = ServerContext.ItemStackFactory.Create(itemId, count);
37	            GetMainInventory(playerId).InsertItem(itemStack);
38	        }
39	
40	        public static async UniTask GiveItemViaCommand(string itemName, int count, float timeoutSeconds)
41	        {
42	            var itemId = ResolveItemId(itemName);
43	            var playerId = ClientContext.PlayerConnectionSetting.PlayerId;
44	            var beforeCount = CountItem(playerId, itemId);
45	
46	            // 本番のgiveコマンド経路で付与し、サーバー在庫への反映を条件待機する
47	            // Grant via the production give-command path and poll until the server inventory reflects it
48	            var command = $"{SendCommandProtocol.GiveCommand} {playerId} {itemId.AsPrimitive()} {count}";
49	            ClientContext.VanillaApi.SendOnly.SendCommand(command);
50	
51	            var startTime = Time.realtimeSinceStartup;
52	            while (CountItem(playerId, itemId) < beforeCount + count)
53	            {
54	                if (Time.realtimeSinceStartup - startTime > timeoutSeconds)
55	                {
56	                    throw new TimeoutException($"give '{itemName}' x{count} not reflected within {timeoutSeconds}s");
57	                }
58	                await UniTask.Yield();
59	            }
60	        }
61	
62	        public static async UniTask GiveItemToHotbar(int hotbarSlot, string itemName, int count, float timeoutSeconds)
63	        {
64	            // HoldingItemId駆動の設置システム用に、ホットバーの特定スロットへ直接セットする
65	            // Set directly into a specific hotbar slot for HoldingItemId-driven place systems
