1	// 歯車チェーンポールのセグメント構築検証（UI経路・複雑シナリオプローブ）:
2	// ポール5本をキーマウス操作のみで設置し、2本連結セグメントと3本連結セグメントを作る。
3	// ポール設置はHoldingItemId駆動（ホットバーのポールアイテム所持で連続延長＝設置＋チェーン自動接続）。
4	// セグメントの分離は「GameScreenへ抜けて起点ポールをリセット」で行う。
5	// Gear chain pole segment probe (UI route, complex scenario):
6	// place 5 poles via key/mouse only, forming one 2-pole and one 3-pole chained segment.
7	// Pole placement is HoldingItemId-driven (holding the pole item enables continuous extension = place + auto-chain).
8	// Segments are separated by exiting to GameScreen, which resets the extension source pole.
9	using Client.Playtest;
10	using Client.Playtest.Operations;
11	using Cysharp.Threading.Tasks;
12	using Game.Gear.Common;
13	using Game.Block.Interface;
14	using UnityEngine;
15	
16	var options = new PlaytestRunOptions { Record = true };
17	return PlaytestRunner.Run("gear-chain-pole-via-ui", options, async p =>
18	{
19	    await p.SetupFlatGround();
20	    p.WarpPlayer(new Vector3(7f, 33.5f, 5f));
21	
22	    // ポールはホットバー1（延長設置でアイテム消費）、チェーンはインベントリ在庫から自動消費される
23	    // Poles go to hotbar slot 1 (consumed by extension placement); chains are auto-consumed from inventory stock
24	    p.UnlockBlock("歯車チェーンポール");
25	    await p.GiveItemToHotbar(0, "歯車チェーンポール", 10);
26	    await p.GiveItem("歯車チェーン", 100);
27	
28	    // ビルドメニューからポールを選択して設置モードへ入り、ホットバー1でポールを手持ちにする
29	    // Enter placement mode via the build menu, then hold the pole with hotbar key 1
30	    await p.OpenBuildMenuAndSelectBlock("歯車チェーンポール");
31	    await p.SelectHotbar(0);
32	
33	    // ポール1本をクリック設置し、サーバー反映とクライアント出現（＝延長起点の確定）を待つ
34	    // Click-place one pole, then wait for server placement and client spawn (which fixes the extension source)
35	    async UniTask PlacePole(Vector3Int origin)
36	    {
37	        await p.AimAtPlaceOrigin("歯車チェーンポール", origin);
